"use strict";parserFactory.register("novelversetranslations.com",()=>new NovelversetranslationsParser);class NovelversetranslationsParser extends WordpressBaseParser{constructor(){super()}async getChapterUrls(e,t){let r=this.extractPartialChapterList(e),a=this.getUrlsOfTocPages(e);return(await this.getChaptersFromAllTocPages(r,this.extractPartialChapterList,a,t)).reverse()}extractPartialChapterList(e){let t=e.querySelector(".lcp_catlist");return util.hyperlinksToChapterList(t)}getUrlsOfTocPages(e){let t=[],r=[...e.querySelectorAll("ul.lcp_paginator a:not(.lcp_nextlink)")].map(e=>e.href);if(0<r.length){let e=new URL(r.pop()),a=this.maxPageId(e);for(let r=2;r<=a;++r)e.searchParams.set("lcp_page0",r),t.push(e.href)}return t}maxPageId(e){let t=new URL(e).searchParams.get("lcp_page0");return parseInt(t)}extractTitleImpl(e){return e.querySelector("h1.page-title")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,".nnl_container"),super.removeUnwantedElementsFromContentElement(e)}findCoverImageUrl(e){return util.getFirstImgSrc(e,".post-media")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".post-content p")]}}